//-------------------------------------------------------------------------
// 벌크하불승인 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveContainerTpchsList = async function () {
  // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
  if (acb_dtCls.getValue() == "01") {
    // 업체확인일자 기준
    let ret = await $c.gus.cfValidate($p, [ed_pchsDeptCd, ed_pchsClntNo, ed_copCoConfirmDtSt, ed_copCoConfirmDtEnd]);
    if (!ret) {
      return false;
    }
    if (!(await $c.gus.cfIsAfterDate($p, ed_copCoConfirmDtSt.getValue(), ed_copCoConfirmDtEnd.getValue()))) {
      await $c.win.alert($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
      ed_copCoConfirmDtSt.focus();
      return;
    }
  } else if (acb_dtCls.getValue() == "02" || acb_dtCls.getValue() == "03") {
    // 실적일자/운송일자 기준
    let ret = await $c.gus.cfValidate($p, [ed_pchsDeptCd, ed_pchsClntNo, ed_wrkDtSt, ed_wrkDtEnd]);
    if (!ret) {
      return false;
    }
    if (!(await $c.gus.cfIsAfterDate($p, ed_wrkDtSt.getValue(), ed_wrkDtEnd.getValue()))) {
      await $c.win.alert($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
      ed_wrkDtSt.focus();
      return;
    }
  }

  // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
  if (cbx_unAdmitIncluYn.getValue() == 0) {
    dma_searchContainerTpchsAdmissionList.set("incluYn", "N");
  } else {
    dma_searchContainerTpchsAdmissionList.set("incluYn", "Y");
  }
  dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
  dma_searchContainerTpchsAdmissionList.set("pchsClntNo", ed_pchsClntNo.getValue());
  dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
  dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
  dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
  dma_searchContainerTpchsAdmissionList.set("pchsDeptCd", ed_pchsDeptCd.getValue());
  $c.sbm.execute($p, sbm_searchContainerTpchsAdmissionList);
};

