  ed_DcScAmount.show();
  ed_DcScAmount.setValue("선택 할증금액 : ");
  ed_selectDcScAmount.setValue($c.gus.cfInsertComma($p, scwin.pchsDcScSelAmt));
  ed_allAmount.show();
